import { Injectable, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../database/prisma.service';
import { CreateVulnerabilityDto, UpdateVulnerabilityDto } from './dto/vulnerability.dto';
import { Severity } from '@prisma/client';

@Injectable()
export class VulnerabilityService {
  constructor(private readonly prisma: PrismaService) {}

  async create(dto: CreateVulnerabilityDto) {
    return this.prisma.vulnerability.create({
      data: {
        targetId: dto.targetId,
        title: dto.title,
        type: dto.type,
        severity: dto.severity as Severity,
        cvssScore: dto.cvssScore,
        description: dto.description,
        remediation: dto.remediation,
      },
    });
  }

  async findAll(targetId?: string, severity?: string) {
    const where: any = {};
    if (targetId) where.targetId = targetId;
    if (severity) where.severity = severity;

    return this.prisma.vulnerability.findMany({
      where,
      include: {
        target: {
          select: { id: true, name: true, scope: true },
        },
      },
      orderBy: [
        { severity: 'asc' }, // CRITICAL first
        { createdAt: 'desc' },
      ],
    });
  }

  async findOne(id: string) {
    const vulnerability = await this.prisma.vulnerability.findUnique({
      where: { id },
      include: {
        target: true,
      },
    });
    if (!vulnerability) {
      throw new NotFoundException('Vulnerability record not found in threat database');
    }
    return vulnerability;
  }

  async update(id: string, dto: UpdateVulnerabilityDto) {
    return this.prisma.vulnerability.update({
      where: { id },
      data: dto,
    });
  }

  async delete(id: string) {
    return this.prisma.vulnerability.delete({ where: { id } });
  }

  async getStats() {
    const total = await this.prisma.vulnerability.count();

    const bySeverity = await this.prisma.vulnerability.groupBy({
      by: ['severity'],
      _count: true,
    });

    const severityMap = bySeverity.reduce((acc, item) => {
      acc[item.severity] = item._count;
      return acc;
    }, {} as Record<string, number>);

    return {
      total,
      critical: severityMap['CRITICAL'] || 0,
      high: severityMap['HIGH'] || 0,
      medium: severityMap['MEDIUM'] || 0,
      low: severityMap['LOW'] || 0,
      informational: severityMap['INFORMATIONAL'] || 0,
    };
  }
}

import { IsString, IsNotEmpty, IsNumber, IsEnum, IsOptional } from 'class-validator';
import { Severity } from '@prisma/client';

export class CreateVulnerabilityDto {
  @IsString()
  @IsNotEmpty()
  targetId: string;

  @IsString()
  @IsNotEmpty()
  title: string;

  @IsString()
  @IsNotEmpty()
  type: string;

  @IsEnum(Severity)
  severity: Severity;

  @IsNumber()
  cvssScore: number;

  @IsString()
  @IsNotEmpty()
  description: string;

  @IsString()
  @IsNotEmpty()
  remediation: string;
}

export class UpdateVulnerabilityDto {
  @IsString()
  @IsOptional()
  title?: string;

  @IsString()
  @IsOptional()
  type?: string;

  @IsEnum(Severity)
  @IsOptional()
  severity?: Severity;

  @IsNumber()
  @IsOptional()
  cvssScore?: number;

  @IsString()
  @IsOptional()
  description?: string;

  @IsString()
  @IsOptional()
  remediation?: string;
}

