// API Client for VulnX Hunter Frontend
const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000/api';

class ApiClient {
  private token: string | null = null;

  constructor() {
    if (typeof window !== 'undefined') {
      this.token = localStorage.getItem('vulnx_token');
    }
  }

  private async request<T>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<T> {
    const headers: HeadersInit = {
      'Content-Type': 'application/json',
      ...options.headers,
    };

    if (this.token) {
      headers['Authorization'] = `Bearer ${this.token}`;
    }

    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      headers,
    });

    if (!response.ok) {
      const error = await response.json().catch(() => ({ message: 'Request failed' }));
      throw new Error(error.message || `HTTP ${response.status}`);
    }

    return response.json();
  }

  // Auth
  async login(email: string, password: string) {
    const data = await this.request<{ token: string; user: any }>('/auth/login', {
      method: 'POST',
      body: JSON.stringify({ email, password }),
    });
    this.token = data.token;
    if (typeof window !== 'undefined') {
      localStorage.setItem('vulnx_token', data.token);
    }
    return data;
  }

  async register(email: string, password: string, name: string) {
    const data = await this.request<{ token: string; user: any }>('/auth/register', {
      method: 'POST',
      body: JSON.stringify({ email, password, name }),
    });
    this.token = data.token;
    if (typeof window !== 'undefined') {
      localStorage.setItem('vulnx_token', data.token);
    }
    return data;
  }

  async getProfile() {
    return this.request<any>('/auth/me');
  }

  logout() {
    this.token = null;
    if (typeof window !== 'undefined') {
      localStorage.removeItem('vulnx_token');
    }
  }

  // Targets
  async getTargets() {
    return this.request<any[]>('/targets');
  }

  async getTarget(id: string) {
    return this.request<any>(`/targets/${id}`);
  }

  async createTarget(data: any) {
    return this.request<any>('/targets', {
      method: 'POST',
      body: JSON.stringify(data),
    });
  }

  async deleteTarget(id: string) {
    return this.request<any>(`/targets/${id}`, {
      method: 'DELETE',
    });
  }

  // Scans
  async triggerScan(targetId: string) {
    return this.request<any>('/scans', {
      method: 'POST',
      body: JSON.stringify({ targetId }),
    });
