// Auth Check Component
export function AuthCheck({ children }: { children: React.ReactNode }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    checkAuth();
  }, []);

  const checkAuth = async () => {
    try {
      const token = localStorage.getItem('vulnx_token');
      if (!token) {
        window.location.href = '/login';
        return;
      }

      // Verify token is valid
      await apiClient.getProfile();
      setIsAuthenticated(true);
    } catch (err) {
      localStorage.removeItem('vulnx_token');
      window.location.href = '/login';
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <LoadingSpinner />;
  if (!isAuthenticated) return null;

  return <>{children}</>;
}

# 🔌 Frontend-Backend Integration Guide

## Overview

This guide shows you how to connect the VulnX Hunter frontend to the backend API, replacing mock data with real API calls.

---

## 📋 Prerequisites

Before starting integration:

- ✅ Backend API running on `http://localhost:8000`
- ✅ Database migrated and seeded
- ✅ Redis running
- ✅ Frontend running on `http://localhost:3000`

---

## 🎯 Integration Steps

### Step 1: Import API Client

In any page component, import the API client:

```typescript
import { apiClient } from '@/lib/api-client';
import { wsClient } from '@/lib/websocket-client';
```

### Step 2: Replace Mock Data

**Before (Mock Data):**
```typescript
const [targets, setTargets] = useState([
  { id: '1', name: 'example.com', scope: 'example.com', ... },
  { id: '2', name: 'test.com', scope: 'test.com', ... },
]);
```

**After (Real API):**
```typescript
const [targets, setTargets] = useState([]);
const [loading, setLoading] = useState(true);

useEffect(() => {
  const fetchTargets = async () => {
    try {
      const data = await apiClient.getTargets();
      setTargets(data);
    } catch (error) {
      console.error('Failed to fetch targets:', error);
    } finally {
      setLoading(false);
    }
  };

  fetchTargets();
}, []);
```

### Step 3: Add Loading States

```typescript
if (loading) {
  return <LoadingSpinner />;
}

if (error) {
  return <ErrorMessage error={error} />;
}

return (
  <div>
    {/* Your component content */}
  </div>
);
```

### Step 4: Add Real-time Updates

```typescript
useEffect(() => {
  // Connect to WebSocket
  wsClient.connect();

  // Listen for scan updates
  wsClient.onScanStatusUpdate((data) => {
    if (data.status === 'COMPLETED') {
      // Refresh data when scan completes
      fetchTargets();
    }
  });

  // Cleanup
  return () => {
    wsClient.off('scanStatusUpdate');
  };
}, []);
```

### Step 5: Handle User Actions

```typescript
const handleTriggerScan = async (targetId: string) => {
  try {
    const scan = await apiClient.triggerScan(targetId);

    // Join scan logs room for real-time updates
    wsClient.joinScanLogs(scan.id);

    // Show success message
    alert('Scan started successfully!');
  } catch (error) {
    alert('Failed to start scan: ' + error.message);
  }
};
```

