'use client';

import React, { useState } from 'react';
import { Shield, Mail, Lock, User, Eye, EyeOff, ArrowRight, CheckCircle2 } from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { apiClient } from '@/lib/api-client';

export default function RegisterPage() {
  const router = useRouter();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prev => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const validateForm = () => {
    if (formData.password.length < 8) {
      setError('Password must be at least 8 characters long');
      return false;
    }
    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match');
      return false;
    }
    return true;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!validateForm()) return;

    setLoading(true);

    try {
      const result = await apiClient.register(
        formData.email,
        formData.password,
        formData.name
      );
      console.log('Registration successful:', result.user);

      // Redirect to dashboard
      router.push('/dashboard');
    } catch (err: any) {
      console.error('Registration failed:', err);
      setError(err.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const passwordStrength = () => {
    const password = formData.password;
    if (password.length === 0) return { strength: 0, label: '', color: '' };
    if (password.length < 8) return { strength: 25, label: 'Weak', color: 'bg-cyber-pink' };
    if (password.length < 12) return { strength: 50, label: 'Fair', color: 'bg-[#FFD600]' };
    if (password.length < 16) return { strength: 75, label: 'Good', color: 'bg-cyber-blue' };
    return { strength: 100, label: 'Strong', color: 'bg-cyber-green' };
  };

  const strength = passwordStrength();

  return (
    <div className="min-h-screen bg-[#050812] flex items-center justify-center p-6 scanline">
      {/* Background Grid Effect */}
      <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,178,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,178,0.03)_1px,transparent_1px)] bg-[size:50px_50px] [mask-image:radial-gradient(ellipse_80%_50%_at_50%_50%,black,transparent)]" />

      <div className="relative w-full max-w-md">
        {/* Logo Header */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center gap-3 mb-4">
            <div className="p-3 bg-gradient-to-br from-cyber-green to-cyber-blue border-2 border-black shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] rounded-sm">
              <Shield className="w-8 h-8 text-black" />
            </div>
          </div>
          <h1 className="font-heading font-extrabold text-3xl text-white tracking-tight mb-2">
            VULNX <span className="text-cyber-green">HUNTER</span>
          </h1>
          <p className="text-xs font-mono text-cyber-muted uppercase tracking-widest">
            Security Testing Platform
          </p>
        </div>

        {/* Register Card */}
        <div className="bg-[#0b1120] border border-white/10 rounded-sm p-8 shadow-2xl">
          <div className="mb-6">
            <h2 className="text-xl font-heading font-bold text-white mb-1">Create Account</h2>
            <p className="text-xs font-mono text-cyber-muted">Join the elite security researchers</p>
          </div>

          {/* Error Message */}
          {error && (
            <div className="mb-6 p-3 bg-cyber-pink/10 border border-cyber-pink/20 rounded-sm">
              <p className="text-xs font-mono text-cyber-pink">{error}</p>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-5">
            {/* Name Input */}
            <div>
              <label className="block text-xs font-mono text-cyber-muted uppercase tracking-wider mb-2">
                Full Name
              </label>
              <div className="relative">
                <User className="absolute left-3 top-3 w-4 h-4 text-cyber-muted" />
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  placeholder="Shadow Hunter"
                  required
                  className="w-full bg-[#050812] border border-white/10 focus:border-cyber-green outline-none py-2.5 pl-10 pr-4 text-sm text-white rounded-sm font-mono placeholder-cyber-muted/50 transition-colors"
                />
              </div>
            </div>

            {/* Email Input */}
            <div>
              <label className="block text-xs font-mono text-cyber-muted uppercase tracking-wider mb-2">
                Email Address
              </label>
              <div className="relative">
                <Mail className="absolute left-3 top-3 w-4 h-4 text-cyber-muted" />
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  placeholder="hacker@vulnx.local"
                  required
                  className="w-full bg-[#050812] border border-white/10 focus:border-cyber-green outline-none py-2.5 pl-10 pr-4 text-sm text-white rounded-sm font-mono placeholder-cyber-muted/50 transition-colors"
                />
              </div>
            </div>

            {/* Password Input */}
            <div>
              <label className="block text-xs font-mono text-cyber-muted uppercase tracking-wider mb-2">
                Password
              </label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 w-4 h-4 text-cyber-muted" />
                <input
                  type={showPassword ? 'text' : 'password'}
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  placeholder="••••••••"
                  required
                  className="w-full bg-[#050812] border border-white/10 focus:border-cyber-green outline-none py-2.5 pl-10 pr-12 text-sm text-white rounded-sm font-mono placeholder-cyber-muted/50 transition-colors"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-3 text-cyber-muted hover:text-white transition-colors"
                >
                  {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                </button>
              </div>

              {/* Password Strength Indicator */}
              {formData.password && (
                <div className="mt-2">
                  <div className="flex items-center justify-between mb-1">
                    <span className="text-[10px] font-mono text-cyber-muted uppercase">Strength</span>
                    <span className={`text-[10px] font-mono font-bold ${strength.color.replace('bg-', 'text-')}`}>
                      {strength.label}
                    </span>
                  </div>
                  <div className="w-full h-1 bg-[#050812] rounded-full overflow-hidden">
                    <div 
                      className={`h-full ${strength.color} transition-all duration-300`}
                      style={{ width: `${strength.strength}%` }}
                    />
                  </div>
                </div>
              )}
            </div>

            {/* Confirm Password Input */}
            <div>
              <label className="block text-xs font-mono text-cyber-muted uppercase tracking-wider mb-2">
                Confirm Password
              </label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 w-4 h-4 text-cyber-muted" />
                <input
                  type={showPassword ? 'text' : 'password'}
                  name="confirmPassword"
                  value={formData.confirmPassword}
                  onChange={handleChange}
                  placeholder="••••••••"
                  required
                  className="w-full bg-[#050812] border border-white/10 focus:border-cyber-green outline-none py-2.5 pl-10 pr-4 text-sm text-white rounded-sm font-mono placeholder-cyber-muted/50 transition-colors"
                />
                {formData.confirmPassword && formData.password === formData.confirmPassword && (
                  <CheckCircle2 className="absolute right-3 top-3 w-4 h-4 text-cyber-green" />
                )}
              </div>
            </div>

            {/* Terms Checkbox */}
            <div>
              <label className="flex items-start gap-2 cursor-pointer">
                <input type="checkbox" required className="mt-1 accent-cyber-green" />
                <span className="text-xs font-mono text-cyber-muted">
                  I agree to the{' '}
                  <Link href="/terms" className="text-cyber-green hover:underline">
                    Terms of Service
                  </Link>{' '}
                  and{' '}
                  <Link href="/privacy" className="text-cyber-green hover:underline">
                    Privacy Policy
                  </Link>
                </span>
              </label>
            </div>

            {/* Submit Button */}
            <button
              type="submit"
              disabled={loading}
              className="w-full bg-cyber-green hover:bg-cyber-green/90 text-black font-heading font-extrabold text-sm uppercase tracking-wider py-3 rounded-sm transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 shadow-[0_0_20px_rgba(0,255,178,0.3)]"
            >
              {loading ? (
                <>
                  <div className="w-4 h-4 border-2 border-black border-t-transparent rounded-full animate-spin" />
                  Creating Account...
                </>
              ) : (
                <>
                  Create Account
                  <ArrowRight className="w-4 h-4" />
                </>
              )}
            </button>
          </form>

          {/* Divider */}
          <div className="relative my-6">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-white/10" />
            </div>
            <div className="relative flex justify-center text-xs">
              <span className="bg-[#0b1120] px-3 font-mono text-cyber-muted uppercase">Or</span>
            </div>
          </div>

          {/* Login Link */}
          <div className="text-center">
            <p className="text-xs font-mono text-cyber-muted">
              Already have an account?{' '}
              <Link href="/login" className="text-cyber-green hover:underline font-bold">
                Sign In
              </Link>
            </p>
          </div>
        </div>

        {/* Footer */}
        <div className="mt-6 text-center">
          <p className="text-[10px] font-mono text-cyber-muted/50">
            Protected by enterprise-grade security • JWT Authentication
          </p>
        </div>
      </div>
    </div>
  );
}
